const input = $input.first().json || {};

// Поддерживаем оба варианта:
// 1) main workflow передал полный Telegram update
// 2) main workflow уже передал нормализованный payload
const msg =
  input.message && input.message.chat && input.message.from
    ? input.message
    : input.telegram_message && input.telegram_message.chat && input.telegram_message.from
      ? input.telegram_message
      : null;

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') return value;
  }
  return null;
}

function basePayload(extra = {}) {
  const userId = firstValue(
    input.user_id,
    msg?.from?.id
  );

  const chatId = firstValue(
    input.chat_id,
    msg?.chat?.id,
    userId
  );

  return {
    user_id: userId,
    chat_id: chatId,

    username: firstValue(input.username, msg?.from?.username, ''),
    first_name: firstValue(input.first_name, msg?.from?.first_name, ''),
    last_name: firstValue(input.last_name, msg?.from?.last_name, ''),

    message: null,
    content: null,
    message_type: 'text',

    file_id: null,
    file_unique_id: null,
    file_name: null,
    mime_type: null,
    caption: null,
    telegram_file_path: null,
    file_url: null,
    file_size: null,

    latitude: null,
    longitude: null,
    location_title: null,
    location_address: null,
    maps_url: null,

    telegram_message: msg || input.telegram_message || null,

    ...extra
  };
}

// Если main workflow уже передал готовый normalized payload
if (!msg) {
  const userId = firstValue(input.user_id, input.from?.id);
  const chatId = firstValue(input.chat_id, input.chat?.id, userId);

  if (!userId || !chatId) {
    throw new Error(
      `No Telegram message or normalized payload found. Input keys: ${Object.keys(input).join(', ')}`
    );
  }

  return [
    {
      json: {
        ...basePayload(),
        ...input,
        user_id: userId,
        chat_id: chatId,
        username: firstValue(input.username, ''),
        first_name: firstValue(input.first_name, ''),
        last_name: firstValue(input.last_name, '')
      }
    }
  ];
}

if (!msg.from?.id || !msg.chat?.id) {
  throw new Error('Telegram message exists, but from.id or chat.id is missing');
}

// Text
if (msg.text) {
  return [
    {
      json: basePayload({
        message_type: 'text',
        message: msg.text,
        content: msg.text
      })
    }
  ];
}

// Location
if (msg.location) {
  const lat = msg.location.latitude;
  const lon = msg.location.longitude;
  const mapsUrl = `https://maps.google.com/?q=${lat},${lon}`;

  return [
    {
      json: basePayload({
        message_type: 'location',
        message: `Shared location: ${mapsUrl}`,
        content: `Shared location: ${mapsUrl}`,
        latitude: lat,
        longitude: lon,
        location_title: msg.venue?.title || null,
        location_address: msg.venue?.address || null,
        maps_url: mapsUrl
      })
    }
  ];
}

// Venue
if (msg.venue) {
  const lat = msg.venue.location.latitude;
  const lon = msg.venue.location.longitude;
  const mapsUrl = `https://maps.google.com/?q=${lat},${lon}`;

  return [
    {
      json: basePayload({
        message_type: 'location',
        message: `Shared venue: ${msg.venue.title || 'Location'}\n${mapsUrl}`,
        content: `Shared venue: ${msg.venue.title || 'Location'}\n${mapsUrl}`,
        latitude: lat,
        longitude: lon,
        location_title: msg.venue.title || null,
        location_address: msg.venue.address || null,
        maps_url: mapsUrl
      })
    }
  ];
}

// Video note
if (msg.video_note) {
  return [
    {
      json: basePayload({
        message_type: 'video_note',
        message: '[video note]',
        content: '[video note]',
        file_id: msg.video_note.file_id,
        file_unique_id: msg.video_note.file_unique_id,
        mime_type: 'video/mp4',
        file_size: msg.video_note.file_size || null,
        caption: null
      })
    }
  ];
}

// Photo
if (msg.photo && msg.photo.length > 0) {
  const photo = msg.photo[msg.photo.length - 1];

  return [
    {
      json: basePayload({
        message_type: 'photo',
        message: msg.caption || '[photo]',
        content: msg.caption || '[photo]',
        file_id: photo.file_id,
        file_unique_id: photo.file_unique_id,
        file_name: 'photo.jpg',
        mime_type: 'image/jpeg',
        file_size: photo.file_size || null,
        caption: msg.caption || null
      })
    }
  ];
}

// Document / file
if (msg.document) {
  return [
    {
      json: basePayload({
        message_type: 'document',
        message: msg.caption || msg.document.file_name || '[document]',
        content: msg.caption || msg.document.file_name || '[document]',
        file_id: msg.document.file_id,
        file_unique_id: msg.document.file_unique_id,
        file_name: msg.document.file_name || null,
        mime_type: msg.document.mime_type || null,
        file_size: msg.document.file_size || null,
        caption: msg.caption || null
      })
    }
  ];
}

// Voice
if (msg.voice) {
  return [
    {
      json: basePayload({
        message_type: 'voice',
        message: msg.caption || '[voice message]',
        content: msg.caption || '[voice message]',
        file_id: msg.voice.file_id,
        file_unique_id: msg.voice.file_unique_id,
        mime_type: msg.voice.mime_type || 'audio/ogg',
        file_size: msg.voice.file_size || null,
        caption: msg.caption || null
      })
    }
  ];
}

// Audio
if (msg.audio) {
  return [
    {
      json: basePayload({
        message_type: 'audio',
        message: msg.caption || msg.audio.file_name || msg.audio.title || '[audio]',
        content: msg.caption || msg.audio.file_name || msg.audio.title || '[audio]',
        file_id: msg.audio.file_id,
        file_unique_id: msg.audio.file_unique_id,
        file_name: msg.audio.file_name || msg.audio.title || null,
        mime_type: msg.audio.mime_type || null,
        file_size: msg.audio.file_size || null,
        caption: msg.caption || null
      })
    }
  ];
}

// Video
if (msg.video) {
  return [
    {
      json: basePayload({
        message_type: 'video',
        message: msg.caption || '[video]',
        content: msg.caption || '[video]',
        file_id: msg.video.file_id,
        file_unique_id: msg.video.file_unique_id,
        mime_type: msg.video.mime_type || 'video/mp4',
        file_size: msg.video.file_size || null,
        caption: msg.caption || null
      })
    }
  ];
}

// Fallback
return [
  {
    json: basePayload({
      message_type: 'unknown',
      message: '[unrecognized message]',
      content: '[unrecognized message]'
    })
  }
];

