const input = $input.first().json || {};

const maxBytes = 1024 * 1024; // 1 MB

const messageType = String(input.message_type || '').toLowerCase();
const fileSize = Number(input.file_size || 0);

const limitedTypes = [
  'document',
  'file',
  'video',
  'video_note'
];

const hasKnownSize = fileSize > 0;
const isLimitedType = limitedTypes.includes(messageType);

const isTooLarge =
  isLimitedType &&
  hasKnownSize &&
  fileSize > maxBytes;

function formatBytes(bytes) {
  const n = Number(bytes || 0);

  if (!n || Number.isNaN(n)) {
    return 'unknown size';
  }

  if (n < 1024) {
    return `${n} B`;
  }

  if (n < 1024 * 1024) {
    return `${(n / 1024).toFixed(1)} KB`;
  }

  return `${(n / 1024 / 1024).toFixed(1)} MB`;
}

function getHumanType(type) {
  if (type === 'document' || type === 'file') return 'file';
  if (type === 'video' || type === 'video_note') return 'video';
  return type || 'file';
}

let unsupportedReason = null;

if (isTooLarge) {
  unsupportedReason =
    `Unsupported file size ⚠️\n\n` +
    `This bot currently supports videos and files up to 1 MB.\n\n` +
    `Your ${getHumanType(messageType)} size: ${formatBytes(fileSize)}.\n\n` +
    `Please send a smaller file, a photo, a voice note, or a text message instead.`;
}

return [
  {
    json: {
      ...input,

      max_supported_file_size_bytes: maxBytes,
      max_supported_file_size_human: formatBytes(maxBytes),

      file_size_supported: !isTooLarge,
      unsupported_large_file: isTooLarge,
      unsupported_reason: unsupportedReason,

      file_size_human: formatBytes(fileSize)
    }
  }
];

const input = $input.first().json || {};

const original =
  typeof input.original_payload === 'object'
    ? input.original_payload
    : {};

return [
  {
    json: {
      ...original,

      ai_usage_id: input.ai_usage_id || null,
      ai_quota_feature: input.feature || 'message_analysis',
      ai_quota_plan: input.plan || 'free',
      ai_quota_limit: Number(input.hourly_limit || 10),
      ai_quota_used: Number(input.used_after_this_request || 0),
      ai_quota_remaining: Number(input.remaining_after_this_request || 0),
      ai_quota_reset_at: input.reset_at || null
    }
  }
];

const input = $input.first().json || {};

const userId = input.user_id;
const chatId = input.chat_id || userId;

function formatReset(value) {
  if (!value) return 'within about 1 hour';

  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return 'within about 1 hour';

  return date.toLocaleTimeString('en-GB', {
    hour: '2-digit',
    minute: '2-digit'
  });
}

const limit = Number(input.hourly_limit || 10);
const used = Number(input.used_last_hour || 0);
const resetAt = formatReset(input.reset_at);

const text =
`AI limit reached.

You used ${used}/${limit} AI requests in the last hour.

Please try again after ${resetAt}.

Regular search by 1–2 words can still work without AI.`;

return [
  {
    json: {
      user_id: userId,
      chat_id: chatId,
      text
    }
  }
];
